sql:
SELECT COUNT(*) AS total_batches
FROM production_batches
WHERE production_location = 'Winery B';

SELECT wine_id, AVG(property_value) AS avg_property_value, COUNT(property_id) AS property_count
FROM chemical_properties
GROUP BY wine_id;

SELECT COUNT(class_id) AS class_count, class_name, origin
FROM wine_classes
GROUP BY class_name, origin;

SELECT AVG(property_value) AS average_alcohol_level
FROM chemical_properties
WHERE property_name = 'Alcohol' AND unit = '%';

SELECT batch_number
FROM production_batches
WHERE batch_status = 'Completed';

SELECT property_name, property_value, unit
FROM chemical_properties
WHERE wine_id = 1;

SELECT class_name, description
FROM wine_classes
WHERE class_id = 1;

SELECT COUNT(test_id) AS test_count
FROM quality_tests
WHERE test_lab = 'Lab B';

SELECT attribute_name, attribute_value, unit, test_method
FROM sensory_attributes
WHERE wine_id = 1;

SELECT attribute_name, AVG(attribute_value) AS average_perception
FROM sensory_attributes
GROUP BY attribute_name;

SELECT class_name, ageing_potential
FROM wine_classes
WHERE ageing_potential = (SELECT MAX(ageing_potential) FROM wine_classes);

SELECT class_name
FROM wine_classes
WHERE ageing_potential = (SELECT MAX(ageing_potential) FROM wine_classes);
